import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validateCreditCard } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const CREDIT_CARD_PATTERN = /\b(?:\d[ -]*?){13,19}\b/g;

export function detectCreditCard(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'creditCard', CREDIT_CARD_PATTERN, 0.9, validateCreditCard, options);
}
