import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const URL_PATTERN =
  /\bhttps?:\/\/[^\s<>"{}|\\^`[\]]+/gi;

export function detectUrl(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'url', URL_PATTERN, 0.9, undefined, options);
}
