import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const DOB_PATTERN =
  /\b(?:0?[1-9]|[12]\d|3[01])[./-](?:0?[1-9]|1[0-2])[./-](?:19|20)\d{2}\b/g;

export function detectDateOfBirth(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'dateOfBirth', DOB_PATTERN, 0.6, undefined, options);
}
