import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validateIban } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const IBAN_PATTERN = /\b[A-Z]{2}\d{2}[A-Z0-9 ]{11,30}\b/gi;

export function detectIban(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(
    input,
    'iban',
    IBAN_PATTERN,
    0.92,
    (value) => validateIban(value),
    options,
  );
}
