import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const COMPANY_NAME_PATTERN =
  /\b[A-ZÄÖÜ][A-Za-zÄÖÜäöüß&.\s-]{2,40}(?:\s(?:GmbH|AG|UG|KG|OHG|e\.V\.|Ltd\.?|Inc\.?|Corp\.?|LLC))\b/g;

export function detectCompanyName(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'companyName', COMPANY_NAME_PATTERN, 0.6, undefined, options);
}
