import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validatePhone } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const PHONE_PATTERN =
  /(?:\+?\d{1,3}[\s.-]?)?(?:\(?\d{2,4}\)?[\s.-]?)?\d{3,4}[\s.-]?\d{3,4}(?:[\s.-]?\d{1,4})?/g;

export function detectPhone(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'phone', PHONE_PATTERN, 0.85, validatePhone, options);
}
