import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

export function detectCustomRegex(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  if (!options?.pattern) {
    return [];
  }
  try {
    const pattern = new RegExp(options.pattern, options.flags ?? 'g');
    return scanRegex(input, 'customRegex', pattern, 0.75, undefined, options);
  } catch {
    return [];
  }
}
