import {
  BnDetectorOptions,
  BnGovernanceDetector,
  BnGovernanceDetectorId,
  BnGovernanceFinding,
} from '@binom/sdk-governance/types';
import { detectEmail } from './detect-email';
import { detectPhone } from './detect-phone';
import { detectIpv4, detectIpv6 } from './detect-ip';
import { detectCreditCard } from './detect-credit-card';
import { detectIban } from './detect-iban';
import { detectUrl } from './detect-url';
import { detectTaxVatId } from './detect-tax-vat-id';
import { detectPassportId } from './detect-passport-id';
import { detectLicensePlate } from './detect-license-plate';
import { detectDateOfBirth } from './detect-date-of-birth';
import { detectPersonName } from './detect-person-name';
import { detectCompanyName } from './detect-company-name';
import { detectPostalAddress } from './detect-postal-address';
import { detectGeoCoordinates } from './detect-geo-coordinates';
import { detectCustomRegex } from './detect-custom-regex';

type DetectorFn = (input: string, options?: BnDetectorOptions) => BnGovernanceFinding[];

const DETECTOR_FNS: Record<BnGovernanceDetectorId, DetectorFn> = {
  email: detectEmail,
  phone: detectPhone,
  ipv4: detectIpv4,
  ipv6: detectIpv6,
  creditCard: detectCreditCard,
  iban: detectIban,
  url: detectUrl,
  taxVatId: detectTaxVatId,
  passportId: detectPassportId,
  licensePlate: detectLicensePlate,
  dateOfBirth: detectDateOfBirth,
  personName: detectPersonName,
  companyName: detectCompanyName,
  postalAddress: detectPostalAddress,
  geoCoordinates: detectGeoCoordinates,
  customRegex: detectCustomRegex,
};

const DETECTOR_PRIORITIES: Record<BnGovernanceDetectorId, number> = {
  iban: 100,
  creditCard: 95,
  email: 90,
  ipv6: 88,
  ipv4: 87,
  phone: 85,
  url: 80,
  taxVatId: 75,
  passportId: 70,
  licensePlate: 65,
  dateOfBirth: 60,
  postalAddress: 55,
  geoCoordinates: 54,
  companyName: 50,
  personName: 45,
  customRegex: 40,
};

export function createBuiltinDetector(id: BnGovernanceDetectorId): BnGovernanceDetector {
  const detectFn = DETECTOR_FNS[id];
  return {
    id,
    priority: DETECTOR_PRIORITIES[id],
    detect: (input, options) => detectFn(input, options),
  };
}

export function getAllBuiltinDetectors(): BnGovernanceDetector[] {
  return (Object.keys(DETECTOR_FNS) as BnGovernanceDetectorId[]).map(createBuiltinDetector);
}
