import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const POSTAL_ADDRESS_PATTERN =
  /\b[A-ZÄÖÜ][a-zäöüß]+(?:straße|str\.|weg|platz|allee)\s+\d+[a-z]?(?:,\s*)?\d{5}\s+[A-ZÄÖÜ][a-zäöüß]+\b/gi;

export function detectPostalAddress(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'postalAddress', POSTAL_ADDRESS_PATTERN, 0.65, undefined, options);
}
