import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const LICENSE_PLATE_PATTERN =
  /\b[A-Z]{1,3}[-\s]?[A-Z]{1,2}\s?\d{1,4}(?:\s?[A-Z]{1,2})?\b/gi;

export function detectLicensePlate(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'licensePlate', LICENSE_PLATE_PATTERN, 0.7, undefined, options);
}
