import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const TAX_VAT_PATTERN =
  /\b(?:DE\d{9}|ATU\d{8}|FR[A-Z0-9]{2}\d{9}|GB(?:\d{9}|\d{12}|GD\d{3}|HA\d{3})|NL\d{9}B\d{2})\b/gi;

export function detectTaxVatId(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'taxVatId', TAX_VAT_PATTERN, 0.8, undefined, options);
}
