import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validateGeoCoordinates } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const GEO_COORD_PATTERN =
  /\b(?:geo:)?[+-]?\d{1,2}\.\d{3,},\s*[+-]?\d{1,3}\.\d{3,}\b/gi;

export function detectGeoCoordinates(
  input: string,
  options?: BnDetectorOptions,
): BnGovernanceFinding[] {
  return scanRegex(input, 'geoCoordinates', GEO_COORD_PATTERN, 0.85, validateGeoCoordinates, options);
}
