import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const PASSPORT_PATTERN = /\b[A-Z]{1,2}\d{6,9}\b/g;

export function detectPassportId(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'passportId', PASSPORT_PATTERN, 0.65, undefined, options);
}
