import {
  BnDetectorOptions,
  BnGovernanceConfig,
  BnGovernanceDetectorId,
  BnGovernanceFinding,
} from '@binom/sdk-governance/types';

let findingCounter = 0;

export function resetFindingCounter(): void {
  findingCounter = 0;
}

export function createFindingId(): string {
  findingCounter += 1;
  return `finding_${findingCounter}`;
}

export function scanRegex(
  input: string,
  type: BnGovernanceDetectorId | string,
  pattern: RegExp,
  confidence: number,
  validate?: (value: string) => boolean,
  options?: BnDetectorOptions,
): BnGovernanceFinding[] {
  const findings: BnGovernanceFinding[] = [];
  const flags = pattern.flags.includes('g') ? pattern.flags : `${pattern.flags}g`;
  const regex = new RegExp(pattern.source, flags);
  let match: RegExpExecArray | null;

  while ((match = regex.exec(input)) !== null) {
    const value = match[0];
    if (validate && !validate(value)) {
      continue;
    }
    const findingConfidence = options?.minConfidence
      ? Math.max(confidence, options.minConfidence)
      : confidence;
    findings.push({
      id: createFindingId(),
      type,
      start: match.index,
      end: match.index + value.length,
      value,
      confidence: findingConfidence,
    });
    if (match.index === regex.lastIndex) {
      regex.lastIndex += 1;
    }
  }

  return findings;
}

export function isDetectorEnabled(
  detectors: Partial<Record<BnGovernanceDetectorId, boolean | BnDetectorOptions>> | undefined,
  id: BnGovernanceDetectorId,
): boolean {
  if (!detectors || !(id in detectors)) {
    return false;
  }
  const entry = detectors[id];
  if (typeof entry === 'boolean') {
    return entry;
  }
  return entry?.enabled !== false;
}

export function getDetectorOptions(
  detectors: Partial<Record<BnGovernanceDetectorId, boolean | BnDetectorOptions>> | undefined,
  id: BnGovernanceDetectorId,
): BnDetectorOptions | undefined {
  if (!detectors) {
    return undefined;
  }
  const entry = detectors[id];
  if (typeof entry === 'object' && entry !== null) {
    return entry;
  }
  return undefined;
}

export function mergeConfig(
  base: BnGovernanceConfig,
  override?: Partial<BnGovernanceConfig>,
): BnGovernanceConfig {
  const merged: BnGovernanceConfig = {
    ...base,
    ...override,
    detectors: {
      ...base.detectors,
      ...override?.detectors,
    },
  };

  if (!merged.placeholderFormat && merged.placeholderTemplate) {
    merged.placeholderFormat = merged.placeholderTemplate;
  }

  return merged;
}
