import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validateIpv4, validateIpv6 } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const IPV4_PATTERN = /\b(?:(?:25[0-5]|2[0-4]\d|[01]?\d?\d)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d?\d)\b/g;
const IPV6_PATTERN =
  /\b(?:[0-9a-fA-F]{1,4}:){7}[0-9a-fA-F]{1,4}\b|\b(?:[0-9a-fA-F]{1,4}:){1,7}:\b|\b::(?:[0-9a-fA-F]{1,4}:){0,6}[0-9a-fA-F]{1,4}\b/g;

export function detectIpv4(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'ipv4', IPV4_PATTERN, 0.95, validateIpv4, options);
}

export function detectIpv6(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'ipv6', IPV6_PATTERN, 0.95, validateIpv6, options);
}
