import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { validateEmail } from '@binom/sdk-governance/validators';
import { scanRegex } from './bn-detector-utils';

const EMAIL_PATTERN =
  /\b[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+\b/g;

export function detectEmail(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'email', EMAIL_PATTERN, 0.95, validateEmail, options);
}
