import { BnDetectorOptions, BnGovernanceFinding } from '@binom/sdk-governance/types';
import { scanRegex } from './bn-detector-utils';

const PERSON_NAME_PATTERN =
  /\b(?:Dr\.|Prof\.)?\s?[A-ZÄÖÜ][a-zäöüß]+(?:\s[A-ZÄÖÜ][a-zäöüß]+){1,2}\b/g;

export function detectPersonName(input: string, options?: BnDetectorOptions): BnGovernanceFinding[] {
  return scanRegex(input, 'personName', PERSON_NAME_PATTERN, 0.55, undefined, options);
}
